--
-- Name: bpp_publication_author_search_text(text, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bpp_publication_author_search_text(p_zapisani_autorzy text, p_autorzy text[]) RETURNS text
    LANGUAGE sql
    AS $$
    SELECT concat_ws(' ', p_zapisani_autorzy, array_to_string(p_autorzy, ' '));
$$;


--
-- Name: bpp_publication_weighted_search_vector(text, text, text, integer, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bpp_publication_weighted_search_vector(p_tytul_oryginalny text, p_tytul text, p_autorzy text, p_rok integer, p_doi text, p_opis_bibliograficzny text) RETURNS tsvector
    LANGUAGE sql
    AS $$
    SELECT
        setweight(
            to_tsvector(
                'bpp_nazwy_wlasne',
                strip_tags(COALESCE(p_tytul_oryginalny, ''))
            ),
            'A'
        ) ||
        setweight(
            to_tsvector(
                'bpp_nazwy_wlasne',
                strip_tags(COALESCE(p_tytul, ''))
            ),
            'A'
        ) ||
        setweight(
            to_tsvector(
                'bpp_nazwy_wlasne',
                strip_tags(COALESCE(p_autorzy, ''))
            ),
            'B'
        ) ||
        setweight(
            to_tsvector(
                'bpp_nazwy_wlasne',
                COALESCE(p_doi, '') || ' ' ||
                regexp_replace(COALESCE(p_doi, ''), '[^[:alnum:]]+', '', 'g')
            ),
            'B'
        ) ||
        setweight(
            to_tsvector('bpp_nazwy_wlasne', COALESCE(p_rok::TEXT, '')),
            'C'
        ) ||
        setweight(
            to_tsvector(
                'bpp_nazwy_wlasne',
                strip_tags(COALESCE(p_opis_bibliograficzny, ''))
            ),
            'D'
        );
$$;


