    LANGUAGE plpgsql
    AS $$
    DECLARE
    BEGIN
      IF current_setting('denorm.flushing', true) IS DISTINCT FROM 'on' THEN
        PERFORM pg_notify('django_denorm_process', '');
      END IF;
      RETURN NEW;
    END;
    $$;


--
-- Name: pg_find_index(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pg_find_index(tabl text, col text) RETURNS SETOF name
    LANGUAGE plpgsql
    AS $_$

BEGIN
RETURN QUERY EXECUTE

'
select
    i.relname as index_name
from
    pg_class t,
    pg_class i,
    pg_index ix,
    pg_attribute a
where
    t.oid = ix.indrelid
    and i.oid = ix.indexrelid
    and a.attrelid = t.oid
    and a.attnum = ANY(ix.indkey)
    and t.relkind = ''r''
    and t.relname = $1
    and a.attname = $2
' USING tabl, col;
RETURN;
END;

$_$;


--
-- Name: strip_tags(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.strip_tags(text) RETURNS text
    LANGUAGE sql
    AS $_$
    SELECT regexp_replace(
        regexp_replace($1,
           E'<[^>]*?(\s* href \s* = \s* ([\'"]) ([^>]*?) ([\'"]) ) [^>]*?>',
           E' (\\3) ',
            'gx'),
        E'(< [^>]*? >)',
        E'',
         'gx')
$_$;


--
-- Name: ts_post_bpp_autor_search(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ts_post_bpp_autor_search() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
  DECLARE
    v TEXT;

  BEGIN
    v :=
      COALESCE(NEW.nazwisko, '') || ' ' ||
      COALESCE(NEW.imiona, '') || ' ' ||
      COALESCE(NEW.poprzednie_nazwiska, '');

    NEW.search := to_tsvector('bpp_nazwy_wlasne', v);

    RETURN NEW;
  END;

  $$;


--
-- Name: ts_post_bpp_jednostka_search(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ts_post_bpp_jednostka_search() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
  DECLARE
    v TEXT;

  BEGIN

    IF NEW.widoczna = FALSE THEN
      NEW.search := NULL;
      RETURN NEW;
    END IF;

    v :=
      COALESCE(NEW.nazwa, '') || ' ' ||
      COALESCE(NEW.opis, '');

    NEW.search := to_tsvector('bpp_nazwy_wlasne', v);

    RETURN NEW;
  END;

  $$;


--
-- Name: ts_post_bpp_patent_search(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ts_post_bpp_patent_search() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.search_index := bpp_publication_weighted_search_vector(
        NEW.tytul_oryginalny,
        NULL,
        bpp_publication_author_search_text(
            NEW.opis_bibliograficzny_zapisani_autorzy_cache,
            NEW.opis_bibliograficzny_autorzy_cache
        ),
        NEW.rok,
        NULL,
        NEW.opis_bibliograficzny_cache
    );

    RETURN NEW;
END;
$$;


