-- Name: bpp_patent_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.bpp_patent_view AS
SELECT
    NULL::integer[] AS id,
    NULL::text AS tytul_oryginalny,
    NULL::text AS tytul,
    NULL::tsvector AS search_index,
    NULL::integer AS rok,
    NULL::integer AS jezyk_id,
    NULL::integer AS typ_kbn_id,
    NULL::integer AS charakter_formalny_id,
    NULL::integer AS zrodlo_id,
    NULL::integer AS wydawnictwo_nadrzedne_id,
    NULL::text AS wydawnictwo,
    NULL::text AS informacje,
    NULL::character varying(512) AS szczegoly,
    NULL::text AS uwagi,
    NULL::numeric(6,3) AS impact_factor,
    NULL::numeric(6,2) AS punkty_kbn,
    NULL::numeric(6,2) AS index_copernicus,
    NULL::numeric(6,2) AS punktacja_wewnetrzna,
    NULL::numeric(6,3) AS punktacja_snip,
    NULL::integer AS kwartyl_w_wos,
    NULL::integer AS kwartyl_w_scopus,
    NULL::text AS adnotacje,
    NULL::timestamp with time zone AS utworzono,
    NULL::timestamp with time zone AS ostatnio_zmieniony,
    NULL::text AS tytul_oryginalny_sort,
    NULL::text AS opis_bibliograficzny_cache,
    NULL::text[] AS opis_bibliograficzny_autorzy_cache,
    NULL::text AS opis_bibliograficzny_zapisani_autorzy_cache,
    NULL::character varying(400) AS slug,
    NULL::boolean AS recenzowana,
    NULL::integer AS liczba_znakow_wydawniczych,
    NULL::character varying(1024) AS www,
    NULL::date AS dostep_dnia,
    NULL::character varying(2048) AS public_www,
    NULL::date AS public_dostep_dnia,
    NULL::integer AS openaccess_czas_publikacji_id,
    NULL::integer AS openaccess_licencja_id,
    NULL::integer AS openaccess_tryb_dostepu_id,
    NULL::integer AS openaccess_wersja_tekstu_id,
    NULL::integer AS openaccess_ilosc_miesiecy,
    NULL::date AS openaccess_data_opublikowania,
    NULL::integer AS konferencja_id,
    NULL::bigint AS liczba_autorow,
    NULL::integer AS liczba_cytowan,
    NULL::integer AS status_korekty_id,
    NULL::text AS doi,
    NULL::text AS pbn_uid_id,
    NULL::text AS isbn,
    NULL::text AS e_isbn,
    NULL::character varying(255)[] AS slowa_kluczowe_eng,
    NULL::integer AS wydawca_id,
    NULL::integer AS object_id_raw;


