--
-- Name: bpp_praca_doktorska_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.bpp_praca_doktorska_view AS
 SELECT ARRAY[( SELECT django_content_type.id
           FROM public.django_content_type
          WHERE (((django_content_type.app_label)::text = 'bpp'::text) AND ((django_content_type.model)::text = 'praca_doktorska'::text))), id] AS id,
    tytul_oryginalny,
    tytul,
    search_index,
    rok,
    jezyk_id,
    typ_kbn_id,
    ( SELECT bpp_charakter_formalny.id
           FROM public.bpp_charakter_formalny
          WHERE ((bpp_charakter_formalny.skrot)::text = 'D'::text)) AS charakter_formalny_id,
    NULL::integer AS zrodlo_id,
    NULL::integer AS wydawnictwo_nadrzedne_id,
    wydawca_opis AS wydawnictwo,
    informacje,
    szczegoly,
    uwagi,
    impact_factor,
    punkty_kbn,
    index_copernicus,
    punktacja_wewnetrzna,
    punktacja_snip,
    NULL::integer AS kwartyl_w_wos,
    NULL::integer AS kwartyl_w_scopus,
    adnotacje,
    utworzono,
    ostatnio_zmieniony,
    tytul_oryginalny_sort,
    opis_bibliograficzny_cache,
    opis_bibliograficzny_autorzy_cache,
    opis_bibliograficzny_zapisani_autorzy_cache,
    slug,
    recenzowana,
    0 AS liczba_znakow_wydawniczych,
    www,
    dostep_dnia,
    public_www,
    public_dostep_dnia,
    NULL::integer AS openaccess_czas_publikacji_id,
    NULL::integer AS openaccess_licencja_id,
    NULL::integer AS openaccess_tryb_dostepu_id,
    NULL::integer AS openaccess_wersja_tekstu_id,
    NULL::integer AS openaccess_ilosc_miesiecy,
    NULL::date AS openaccess_data_opublikowania,
    NULL::integer AS konferencja_id,
    1 AS liczba_autorow,
    liczba_cytowan,
    status_korekty_id,
    lower((doi)::text) AS doi,
    pbn_uid_id,
    replace(replace(replace((isbn)::text, '-'::text, ''::text), ' '::text, ''::text), '.'::text, ''::text) AS isbn,
    replace(replace(replace((e_isbn)::text, '-'::text, ''::text), ' '::text, ''::text), '.'::text, ''::text) AS e_isbn,
    slowa_kluczowe_eng,
    NULL::integer AS wydawca_id,
    id AS object_id_raw
   FROM public.bpp_praca_doktorska;


--
-- Name: bpp_praca_habilitacyjna_id_seq; Type: SEQUENCE; Schema: public; Owner: -
--

ALTER TABLE public.bpp_praca_habilitacyjna ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (
    SEQUENCE NAME public.bpp_praca_habilitacyjna_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: bpp_praca_habilitacyjna_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.bpp_praca_habilitacyjna_view AS
 SELECT ARRAY[( SELECT django_content_type.id
           FROM public.django_content_type
          WHERE (((django_content_type.app_label)::text = 'bpp'::text) AND ((django_content_type.model)::text = 'praca_habilitacyjna'::text))), id] AS id,
    tytul_oryginalny,
    tytul,
    search_index,
    rok,
    jezyk_id,
    typ_kbn_id,
    ( SELECT bpp_charakter_formalny.id
           FROM public.bpp_charakter_formalny
          WHERE ((bpp_charakter_formalny.skrot)::text = 'H'::text)) AS charakter_formalny_id,
    NULL::integer AS zrodlo_id,
    NULL::integer AS wydawnictwo_nadrzedne_id,
    wydawca_opis AS wydawnictwo,
    informacje,
    szczegoly,
    uwagi,
    impact_factor,
    punkty_kbn,
    index_copernicus,
    punktacja_wewnetrzna,
    punktacja_snip,
    NULL::integer AS kwartyl_w_wos,
    NULL::integer AS kwartyl_w_scopus,
    adnotacje,
    utworzono,
    ostatnio_zmieniony,
    tytul_oryginalny_sort,
    opis_bibliograficzny_cache,
    opis_bibliograficzny_autorzy_cache,
    opis_bibliograficzny_zapisani_autorzy_cache,
    slug,
    recenzowana,
    0 AS liczba_znakow_wydawniczych,
    www,
    dostep_dnia,
    public_www,
    public_dostep_dnia,
    NULL::integer AS openaccess_czas_publikacji_id,
    NULL::integer AS openaccess_licencja_id,
    NULL::integer AS openaccess_tryb_dostepu_id,
    NULL::integer AS openaccess_wersja_tekstu_id,
    NULL::integer AS openaccess_ilosc_miesiecy,
    NULL::date AS openaccess_data_opublikowania,
    NULL::integer AS konferencja_id,
    1 AS liczba_autorow,
    liczba_cytowan,
    status_korekty_id,
    lower((doi)::text) AS doi,
    pbn_uid_id,
    replace(replace(replace((isbn)::text, '-'::text, ''::text), ' '::text, ''::text), '.'::text, ''::text) AS isbn,
    replace(replace(replace((e_isbn)::text, '-'::text, ''::text), ' '::text, ''::text), '.'::text, ''::text) AS e_isbn,
    slowa_kluczowe_eng,
    NULL::integer AS wydawca_id,
    id AS object_id_raw
   FROM public.bpp_praca_habilitacyjna;


--
-- Name: bpp_publikacja_habilitacyjna; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.bpp_publikacja_habilitacyjna (
    id integer NOT NULL,
    kolejnosc integer NOT NULL,
    object_id integer NOT NULL,
    content_type_id integer NOT NULL,
    praca_habilitacyjna_id integer NOT NULL,
    CONSTRAINT bpp_publikacja_habilitacyjna_object_id_check CHECK ((object_id >= 0))
);


