--
-- Name: bpp_uczelnia_ewaluacja_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.bpp_uczelnia_ewaluacja_view AS
 SELECT ARRAY[bpp_rekord_mat.id[1], bpp_rekord_mat.id[2], bpp_autorzy_mat.autor_id, bpp_autorzy_mat.kolejnosc] AS id,
    bpp_rekord_mat.id AS rekord_id,
    bpp_autorzy_mat.id AS autorzy_id,
    bpp_autor_dyscyplina.id AS autor_dyscyplina_id,
    bpp_cache_punktacja_dyscypliny.autorzy_z_dyscypliny,
    bpp_cache_punktacja_autora.pkdaut,
    bpp_cache_punktacja_autora.slot
   FROM ((((public.bpp_rekord_mat
     JOIN public.bpp_autorzy_mat ON ((bpp_rekord_mat.id = bpp_autorzy_mat.rekord_id)))
     JOIN public.bpp_cache_punktacja_dyscypliny ON (((bpp_cache_punktacja_dyscypliny.dyscyplina_id = bpp_autorzy_mat.dyscyplina_naukowa_id) AND (bpp_cache_punktacja_dyscypliny.rekord_id = bpp_autorzy_mat.rekord_id))))
     JOIN public.bpp_cache_punktacja_autora ON (((bpp_cache_punktacja_autora.rekord_id = bpp_autorzy_mat.rekord_id) AND (bpp_cache_punktacja_autora.autor_id = bpp_autorzy_mat.autor_id))))
     JOIN public.bpp_autor_dyscyplina ON (((bpp_autor_dyscyplina.autor_id = bpp_autorzy_mat.autor_id) AND (bpp_autor_dyscyplina.rok = bpp_rekord_mat.rok))));


