--

CREATE VIEW public.bpp_zewnetrzne_bazy_wydawnictwo_ciagle_view AS
 SELECT ARRAY[( SELECT django_content_type.id
           FROM public.django_content_type
          WHERE (((django_content_type.app_label)::text = 'bpp'::text) AND ((django_content_type.model)::text = 'wydawnictwo_ciagle'::text))), rekord_id] AS rekord_id,
    baza_id,
    info
   FROM public.bpp_wydawnictwo_ciagle_zewnetrzna_baza_danych;


--
-- Name: bpp_zewnetrzne_bazy_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.bpp_zewnetrzne_bazy_view AS
 SELECT rekord_id,
    baza_id,
    info
   FROM public.bpp_zewnetrzne_bazy_wydawnictwo_ciagle_view;


