--
-- Name: rozbieznosci_dyscyplin_brakprzypisaniaview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.rozbieznosci_dyscyplin_brakprzypisaniaview AS
 SELECT ARRAY[bpp_rekord_mat.id[1], bpp_rekord_mat.id[2], bpp_autorzy_mat.autor_id] AS id,
    bpp_rekord_mat.id AS rekord_id,
    bpp_rekord_mat.rok,
    bpp_autorzy_mat.autor_id,
    bpp_autorzy_mat.dyscyplina_naukowa_id AS dyscyplina_rekordu_id,
    NULL::integer AS dyscyplina_autora_id,
    NULL::integer AS subdyscyplina_autora_id
   FROM public.bpp_rekord_mat,
    public.bpp_autorzy_mat
  WHERE ((bpp_autorzy_mat.rekord_id = bpp_rekord_mat.id) AND (bpp_autorzy_mat.dyscyplina_naukowa_id IS NOT NULL) AND (bpp_rekord_mat.rok >= 2017) AND (NOT (EXISTS ( SELECT bpp_autor_dyscyplina.id
           FROM public.bpp_autor_dyscyplina
          WHERE ((bpp_autor_dyscyplina.rok = bpp_rekord_mat.rok) AND (bpp_autor_dyscyplina.autor_id = bpp_autorzy_mat.autor_id))))));


--
-- Name: rozbieznosci_dyscyplin_rozbiezneprzypisaniaview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.rozbieznosci_dyscyplin_rozbiezneprzypisaniaview AS
 SELECT ARRAY[bpp_rekord_mat.id[1], bpp_rekord_mat.id[2], bpp_autorzy_mat.autor_id] AS id,
    bpp_rekord_mat.id AS rekord_id,
    bpp_rekord_mat.rok,
    bpp_autorzy_mat.autor_id,
    bpp_autorzy_mat.dyscyplina_naukowa_id AS dyscyplina_rekordu_id,
    bpp_autor_dyscyplina.dyscyplina_naukowa_id AS dyscyplina_autora_id,
    bpp_autor_dyscyplina.subdyscyplina_naukowa_id AS subdyscyplina_autora_id
   FROM public.bpp_autorzy_mat,
    public.bpp_autor_dyscyplina,
    public.bpp_rekord_mat
  WHERE ((bpp_rekord_mat.id = bpp_autorzy_mat.rekord_id) AND (bpp_rekord_mat.rok >= 2017) AND (bpp_rekord_mat.id[1] IN ( SELECT django_content_type.id
           FROM public.django_content_type
          WHERE (((django_content_type.app_label)::text = 'bpp'::text) AND (((django_content_type.model)::text = 'wydawnictwo_zwarte'::text) OR ((django_content_type.model)::text = 'wydawnictwo_ciagle'::text))))) AND (bpp_rekord_mat.rok = bpp_autor_dyscyplina.rok) AND (bpp_autorzy_mat.autor_id = bpp_autor_dyscyplina.autor_id) AND ((bpp_autorzy_mat.dyscyplina_naukowa_id IS NULL) OR ((bpp_autorzy_mat.dyscyplina_naukowa_id IS DISTINCT FROM bpp_autor_dyscyplina.dyscyplina_naukowa_id) AND (bpp_autorzy_mat.dyscyplina_naukowa_id IS DISTINCT FROM bpp_autor_dyscyplina.subdyscyplina_naukowa_id))));


--
-- Name: rozbieznosci_dyscyplin_rozbieznosciview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.rozbieznosci_dyscyplin_rozbieznosciview AS
 SELECT rozbieznosci_dyscyplin_brakprzypisaniaview.id,
    rozbieznosci_dyscyplin_brakprzypisaniaview.rekord_id,
    rozbieznosci_dyscyplin_brakprzypisaniaview.rok,
    rozbieznosci_dyscyplin_brakprzypisaniaview.autor_id,
    rozbieznosci_dyscyplin_brakprzypisaniaview.dyscyplina_rekordu_id,
    rozbieznosci_dyscyplin_brakprzypisaniaview.dyscyplina_autora_id,
    rozbieznosci_dyscyplin_brakprzypisaniaview.subdyscyplina_autora_id
   FROM public.rozbieznosci_dyscyplin_brakprzypisaniaview
UNION ALL
 SELECT rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.id,
    rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.rekord_id,
    rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.rok,
    rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.autor_id,
    rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.dyscyplina_rekordu_id,
    rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.dyscyplina_autora_id,
    rozbieznosci_dyscyplin_rozbiezneprzypisaniaview.subdyscyplina_autora_id
   FROM public.rozbieznosci_dyscyplin_rozbiezneprzypisaniaview;


--
-- Name: rozbieznosci_dyscyplin_rozbieznoscizrodelview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.rozbieznosci_dyscyplin_rozbieznoscizrodelview AS
 SELECT DISTINCT ARRAY[bpp_dyscyplina_zrodla.zrodlo_id, bpp_wydawnictwo_ciagle.id, bpp_wydawnictwo_ciagle_autor.autor_id, COALESCE(bpp_wydawnictwo_ciagle_autor.dyscyplina_naukowa_id, '-1'::integer)] AS id,
    bpp_dyscyplina_zrodla.zrodlo_id,
    bpp_wydawnictwo_ciagle.rok,
    bpp_wydawnictwo_ciagle.id AS wydawnictwo_ciagle_id,
    bpp_wydawnictwo_ciagle_autor.autor_id,
    bpp_wydawnictwo_ciagle_autor.dyscyplina_naukowa_id,
    bpp_wydawnictwo_ciagle.punkty_kbn,
    bpp_wydawnictwo_ciagle.charakter_formalny_id
   FROM public.bpp_wydawnictwo_ciagle_autor,
    public.bpp_dyscyplina_zrodla,
    public.bpp_wydawnictwo_ciagle
  WHERE ((bpp_dyscyplina_zrodla.zrodlo_id = bpp_wydawnictwo_ciagle.zrodlo_id) AND (bpp_wydawnictwo_ciagle.rok >= 2017) AND (bpp_wydawnictwo_ciagle_autor.rekord_id = bpp_wydawnictwo_ciagle.id) AND (NOT (bpp_wydawnictwo_ciagle_autor.dyscyplina_naukowa_id IN ( SELECT bpp_dyscyplina_zrodla_1.dyscyplina_id
           FROM public.bpp_dyscyplina_zrodla bpp_dyscyplina_zrodla_1
          WHERE ((bpp_dyscyplina_zrodla_1.zrodlo_id = bpp_wydawnictwo_ciagle.zrodlo_id) AND (bpp_dyscyplina_zrodla_1.rok = bpp_wydawnictwo_ciagle.rok))))));


